const incoming = $input.first().json;
const body = incoming.body || incoming.data || incoming;

let phone = '';
if (body.key && body.key.remoteJid) {
  phone = body.key.remoteJid;
} else if (body.from) {
  phone = body.from;
}
phone = phone.replace('@c.us', '').replace('@s.whatsapp.net', '');

let message = '';
if (body.message && body.message.conversation) {
  message = body.message.conversation;
} else if (body.message && body.message.extendedTextMessage) {
  message = body.message.extendedTextMessage.text;
} else if (body.body) {
  message = body.body;
} else if (body.text) {
  message = body.text;
}

let customerName = 'عميل تجريبي';
if (body.pushName) {
  customerName = body.pushName;
} else if (body.notifyName) {
  customerName = body.notifyName;
}

const chatId = phone + '@s.whatsapp.net';

return {
  json: {
    phone: phone,
    message: message,
    customerName: customerName,
    chatId: chatId,
    intent: 'inquiry',
    timestamp: new Date().toISOString()
  }
};

const parsedMessage = $('2. Message Parser').first().json;
const mockData = $('3. [MOCK] Memory Data').first().json;

const sessionContext = {
  phone: parsedMessage.phone,
  customerName: mockData.customerName || parsedMessage.customerName,
  currentMessage: parsedMessage.message,
  intent: 'inquiry',
  chatId: parsedMessage.chatId,
  timestamp: parsedMessage.timestamp,
  memoryContext: mockData.memoryContext,
  memoryCount: 1,
  sessionId: `debug_session_${parsedMessage.phone}`
};

return { json: sessionContext };

